INSERT INTO "Stations" ("Name", "City", "PictureUrl", "Hint", "LastTimePlayed", "RandomX", "RandomY") VALUES
                                                                                    ('Gare du Nord', 'Paris', '1', 'Gare la plus fréquentée d''Europe', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Lyon', 'Paris', '2', 'Le célèbre Train Bleu', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare Montparnasse', 'Paris', '3', 'Un train a traversé sa façade en 1985', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de l''Est', 'Paris', '4', 'Gare de départ des soldats de la 2nd Guerre Mondiale.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare Saint-Lazare', 'Paris', '5', 'A inspirée une série de toiles de Claude Monet', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare d''Austerlitz', 'Paris', '6', 'Elle porte le nom de la victoire la plus éclatante de Napoléon.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare Saint-Charles', 'Marseille', '7', 'Du centre ville à la gare en 104 marches.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Lyon-Part-Dieu', 'Lyon', '8', 'Inaugurée en 1983, elle est aujourd''hui l''une des gares TGV les plus fréquentées de France, au cœur du deuxième pôle économique du pays.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Lyon-Perrache', 'Lyon', '9', 'Construite en 1857, cette gare historique se situe sur la presqu''île entre le Rhône et la Saône, symbole de la ville aux deux fleuves.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Toulouse-Matabiau', 'Toulouse', '10', 'Gare de la ville rose.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Nice-Ville', 'Nice', '11', 'À deux pas de la Méditerranée, cette gare accueille des voyageurs venus profiter de la Côte d''Azur depuis plus de 150 ans.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Nantes', 'Nantes', '12', 'Construite au XIXe siècle, elle se trouve dans la ville qui fut autrefois la capitale du duché de Bretagne et un grand port négrier.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Montpellier-Saint-Roch', 'Montpellier', '13', 'Elle tient son nom d''une chapelle dédiée au saint patron des pèlerins qui se trouvait autrefois à cet emplacement.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Strasbourg', 'Strasbourg', '14', 'Sa verrière moderne de 2007, en forme de bouclier géant, recouvre la façade wilhelmienne d''origine, symbole du destin franco-allemand de la ville.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Bordeaux-Saint-Jean', 'Bordeaux', '5', 'Depuis 2017, le TGV relie cette gare à Paris en seulement 2h04, plaçant la capitale mondiale du vin à portée d''une pause déjeuner.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Lille-Flandres', 'Lille', '16', 'Sa façade néo-flamande est en réalité l''ancienne gare de Paris-Nord, démontée et reconstruite pierre par pierre à Lille en 1865.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Lille-Europe', 'Lille', '17', 'Inaugurée en 1994 pour l''Eurostar, elle est l''une des rares gares françaises conçues dès l''origine pour les trains internationaux à grande vitesse.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Rennes', 'Rennes', '18', 'Depuis 2017, elle est à 1h25 de Paris grâce à la LGV Bretagne, faisant de la capitale bretonne l''une des villes les mieux connectées à la capitale.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Reims', 'Reims', '19', 'À quelques minutes à pied de la cathédrale où furent sacrés les rois de France, elle accueille les amateurs de champagne du monde entier.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare du Havre', 'Le Havre', '20', 'Reconstruite après la Seconde Guerre mondiale comme toute la ville, classée à l''UNESCO, elle reflète le style de béton brut d''Auguste Perret.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Saint-Étienne-Châteaucreux', 'Saint-Étienne', '21', 'Saint-Étienne est la première ville de France à avoir eu une ligne de chemin de fer, en 1827, bien avant Paris.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Toulon', 'Toulon', '22', 'Dans la ville qui abrite la plus grande base navale de France, la gare est le point de départ idéal pour explorer le littoral varois.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Grenoble', 'Grenoble', '23', 'Entourée par trois massifs alpins, la gare de la capitale des Alpes françaises est la porte d''entrée vers les plus grands domaines skiables d''Europe.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Dijon-Ville', 'Dijon', '24', 'Au cœur de la Bourgogne, cette gare est le point de départ idéal pour explorer les vignobles de la Côte d''Or classés au patrimoine mondial de l''UNESCO.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare d''Angers-Saint-Laud', 'Angers', '25', 'Son nom vient de Saint-Laud, évêque d''Angers au Ve siècle, dont les reliques étaient conservées dans une chapelle voisine.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Nîmes', 'Nîmes', '26', 'Dans la ville aux arènes romaines les mieux conservées du monde, la gare côtoie un patrimoine antique exceptionnel à quelques minutes à pied.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Clermont-Ferrand', 'Clermont-Ferrand', '27', 'Construite en pierre de lave noire volcanique locale, elle est à l''image d''une ville bâtie sur les flanc d''un ancien volcan, la chaîne des Puys.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare du Mans', 'Le Mans', '28', 'La ville est célèbre pour ses 24 Heures mais c''est aussi ici qu''est née la reine Bérengère, seule reine d''Angleterre née en France.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Brest', 'Brest', '29', 'À la pointe du Finistère, c''est l''une des gares les plus à l''ouest de France continentale, terminus au bord de l''Atlantique.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Tours', 'Tours', '30', 'Au cœur du Val de Loire classé à l''UNESCO, la gare donne accès à une concentration unique de châteaux royaux dans un rayon de 50 km.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare d''Amiens', 'Amiens', '31', 'La ville abrite la plus grande cathédrale gothique de France et Jules Verne y vécut 18 ans, écrivant la majorité de ses romans.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Limoges-Bénédictins', 'Limoges', '32', 'Souvent classée parmi les plus belles gares du monde, sa coupole byzantine de 57 mètres et son campanile en font un chef-d''œuvre architectural de 1929.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Perpignan', 'Perpignan', '33', 'Salvador Dalí a déclaré que cette gare était "le centre du monde", lui consacrant même un tableau. Une plaque commémore cette déclaration sur le quai.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Metz-Ville', 'Metz', '34', 'Disqualifiée des plus belles gare de France', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Besançon-Viotte', 'Besançon', '35', 'Dans la ville natale de Victor Hugo et de la montre française, elle jouxte une citadelle Vauban classée au patrimoine mondial de l''UNESCO.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare d''Orléans', 'Orléans', '36', 'Dans la ville libérée par Jeanne d''Arc en 1429, la gare est le point de départ de la découverte du Val de Loire et de son histoire royale.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Rouen-Rive-Droite', 'Rouen', '37', 'Dans la ville où fut brûlée Jeanne d''Arc en 1431, Claude Monet a peint sa célèbre série de la cathédrale depuis un immeuble situé à deux pas de la gare.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Mulhouse-Ville', 'Mulhouse', '38', 'La ville alsacienne abrite la Cité du Train, le plus grand musée ferroviaire de France, à quelques minutes à pied de la gare.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Caen', 'Caen', '39', 'Symbole de reconstruction, la gare de la capitale normande a été entièrement rebâtie après les bombardements de 1944 qui ont détruit 75% de la ville.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Nancy-Ville', 'Nancy', '40', 'À quelques pas de la Place Stanislas, classée au patrimoine mondial de l''UNESCO et considérée comme l''une des plus belles places d''Europe.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Roubaix', 'Roubaix', '41', 'Ancienne capitale mondiale du textile, Roubaix abrite aujourd''hui La Piscine, un musée d''art installé dans une ancienne piscine Art déco de 1932.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare d''Avignon-Centre', 'Avignon', '42', 'À deux pas du Palais des Papes, plus grand palais gothique du monde, et du célèbre pont Saint-Bénézet dont la chanson a fait le tour du monde.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Poitiers', 'Poitiers', '43', 'La ville a vu Charles Martel stopper l''avancée des armées arabes en 732, un des tournants majeurs de l''histoire de l''Occident chrétien.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Pau', 'Pau', '44', 'Depuis son boulevard des Pyrénées, considéré comme le plus beau balcon de France, on aperçoit le pic du Midi d''Ossau par temps clair.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare d''Aix-en-Provence', 'Aix-en-Provence', '45', 'Ville de Cézanne et du festival de musique le plus prestigieux de France, elle est aussi la capitale historique de la Provence.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Tourcoing', 'Tourcoing', '46', 'Jumelle de Roubaix dans la métropole lilloise, cette ville frontalière avec la Belgique fut l''une des capitales mondiales du textile au XIXe siècle.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Dunkerque', 'Dunkerque', '47', 'En 1940, l''opération Dynamo a permis d''évacuer 338 000 soldats alliés depuis ses plages, un exploit rendu célèbre par le film de Christopher Nolan.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Versailles-Chantiers', 'Versailles', '48', 'À quelques minutes du château le plus visité du monde, construit par Louis XIV qui voulait loger toute la cour royale sous un même toit.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Bourges', 'Bourges', '49', 'Capitale du Berry, sa cathédrale gothique Saint-Étienne est classée à l''UNESCO, et la ville accueille le Printemps de Bourges, l''un des plus grands festivals de musique de France.', '2000-01-01', 0.0, 0.0),
                                                                                    ('Gare de Béziers', 'Béziers', '50', 'La ville occitane surplombe le canal du Midi, chef-d''œuvre de Vauban classé à l''UNESCO, et est la capitale mondiale du rugby à XIII.', '2000-01-01', 0.0, 0.0);
